insert into public.procedure_guides (slug, name, jurisdiction, entity_type, description, blueprint)
values

(
  'jamaica-ltd-privacy',
  'Jamaica Ltd — Privacy & Compliance',
  'Jamaica',
  'Ltd',
  'Data protection and publish obligations for a Jamaica Limited Company that processes personal data of Jamaican residents. Guides OIC registration, policy publication, and proof upload. Does not provide legal advice.',
  '{"id":"jamaica-ltd-privacy","procedure_kind":"compliance","pipeline_step":6,"name":"Jamaica Ltd — Privacy & Compliance","jurisdiction":"Jamaica","entity_type":"Ltd","formation_slug":"jamaica-ltd","description":"Data protection and publish obligations for a Jamaica Limited Company that processes personal data of Jamaican residents. Guides OIC registration, policy publication, and proof upload. Does not provide legal advice.","last_researched":"2026-06-18","estimated_total_time":"3–10 business days (OIC processing + policy publish)","estimated_total_cost":"OIC annual fee ~JMD $25,000; Termly free tier or paid plan","legal_basis":["JDPA 2020 (in force December 2023)"],"intake_questions":[{"id":"sells_to","label":"Who do you sell to?","type":"select","required":true,"options":["B2B","Consumers","Both"],"maps_to":"clients.sells_to","affects":["privacy_policy template","cookie_consent required if Consumers or Both"]},{"id":"has_website","label":"Do you have a public website or app?","type":"boolean","required":true,"affects":["privacy_policy","cookie_consent","terms_of_service"]},{"id":"uses_analytics","label":"Do you use analytics or marketing cookies (Google Analytics, Meta Pixel, etc.)?","type":"boolean","required":true,"show_if":{"has_website":true},"affects":["cookie_consent"]},{"id":"has_employees","label":"Do you have or plan to hire employees in Jamaica within 12 months?","type":"boolean","required":true,"affects":["employee_privacy_notice"]},{"id":"processes_jamaica_residents","label":"Do you collect personal data from Jamaican residents (customers, users, employees)?","type":"boolean","required":true,"default":true,"affects":["oic_registration"]},{"id":"website_url","label":"Public website URL (where policy will be linked)","type":"url","required":false,"show_if":{"has_website":true}}],"steps":[{"id":"compliance_intake","title":"Complete compliance intake","description":"Answer intake questions so the checklist reflects your business model. Required before other steps unlock.","required":true,"action_type":"intake","accept":["all required intake_questions answered"]},{"id":"oic_registration","title":"Register as Data Controller with OIC","description":"Mandatory if you process personal data of Jamaican residents. Register with the Office of the Information Commissioner and pay the annual fee.","required":true,"required_if":{"processes_jamaica_residents":true},"estimated_fee":"~JMD $25,000 annual","action_type":"artifact","artifact_kind":"jamaica_oic_registration","url":"https://www.oic.gov.jm","cta":"Open OIC portal","processing_time":"Varies; allow several business days","accept":["artifact_kind jamaica_oic_registration status active","registration number recorded"],"vault_proof":{"category":"compliance_oic","label":"OIC registration confirmation","required":true},"penalty_note":"Fines up to 4% global turnover or JMD 5 million, whichever is higher."},{"id":"privacy_policy","title":"Publish Privacy Policy","description":"JDPA-compliant privacy policy stating legal basis, categories collected, retention, rights, and contact for data subjects.","required":true,"action_type":"artifact","artifact_kind":"privacy_policy","partner":{"slug":"termly","mode":"manual_v1","url":"https://termly.io","cta":"Open Termly"},"accept":["hosted_url set OR artifact_path uploaded","status active","effective_at recorded"],"vault_proof":{"category":"compliance_policy","label":"Published privacy policy PDF","required":false},"note":"Link policy from website footer and signup flows. Version by effective date."},{"id":"terms_of_service","title":"Publish Terms of Service","description":"Website terms with clear scope of service. Not legal advice disclaimer if you offer software or formation adjacent services.","required":true,"required_if":{"has_website":true},"action_type":"artifact","artifact_kind":"terms_of_service","partner":{"slug":"termly","mode":"manual_v1","url":"https://termly.io","cta":"Open Termly"},"accept":["hosted_url set OR artifact_path uploaded","status active"]},{"id":"cookie_consent","title":"Deploy cookie consent banner","description":"Required if site uses non-essential cookies or tracks consumers.","required":false,"required_if":{"uses_analytics":true},"action_type":"artifact","artifact_kind":"cookie_consent_config","partner":{"slug":"termly","mode":"manual_v1","url":"https://termly.io/products/cookie-consent-manager/","cta":"Open Termly cookie manager"},"accept":["hosted_url or embed confirmed","status active"],"note":"Paste Termly embed snippet on site. Screenshot or URL proof acceptable in v1."},{"id":"employee_privacy_notice","title":"Employee privacy notice","description":"If hiring in Jamaica, provide employees a privacy notice covering payroll and HR data.","required":false,"required_if":{"has_employees":true},"action_type":"artifact","artifact_kind":"employee_privacy_notice","template_source":"documents/Client Step 06 Templates/Employee Privacy Notice - Jamaica.md","accept":["artifact_path uploaded OR hosted_url","status active"]},{"id":"retention_schedule","title":"Document retention schedule","description":"Internal one-pager: how long you keep customer, employee, and formation records. Referenced in privacy policy.","required":true,"action_type":"upload","artifact_kind":"retention_schedule","template_source":"documents/Client Step 06 Templates/Retention Schedule.md","accept":["artifact_path uploaded","status active"],"vault_proof":{"category":"compliance_retention","label":"Retention schedule","required":true}},{"id":"breach_process","title":"Define breach response steps","description":"Internal checklist: contain, assess, notify OIC and affected persons within JDPA timelines if required.","required":true,"action_type":"upload","artifact_kind":"breach_response_plan","template_source":"documents/Client Step 06 Templates/Breach Response Plan.md","accept":["artifact_path uploaded","status active"],"note":"Onboardin provides template in v1; counsel review optional upgrade."}],"accept_criteria":["compliance_intake complete","privacy_policy active","oic_registration active when processes_jamaica_residents is true","terms_of_service active when has_website is true","cookie_consent active when uses_analytics is true","employee_privacy_notice active when has_employees is true","retention_schedule active","breach_process active"],"recurring_obligation_seeds":[{"slug":"oic-annual-renewal","title":"OIC annual registration renewal","authority":"OIC","frequency":"annual","note":"Seed into compliance_obligations when lifecycle becomes active (Ticket #08)."}],"agent_instructions":["You guide Jamaica Ltd clients through the jamaica-ltd-privacy procedure only.","Do not invent legal requirements outside this blueprint.","OIC registration is mandatory when processing Jamaican resident data.","Termly is manual in v1: client generates policy externally, then uploads proof or URL.","Do not provide legal advice. Escalate edge cases to concierge."]}'::jsonb
),

(
  'us-de-c-corp-privacy',
  'US Delaware C-Corp — Privacy & Compliance',
  'Delaware',
  'C-Corp',
  'Federal and state privacy and transparency obligations for a Delaware C-Corporation. Covers BOI/FinCEN CTA, published policies, and B2B DPA when applicable. Does not provide legal advice.',
  '{"id":"us-de-c-corp-privacy","procedure_kind":"compliance","pipeline_step":6,"name":"US Delaware C-Corp — Privacy & Compliance","jurisdiction":"Delaware","entity_type":"C-Corp","formation_slug":"us-de-c-corp","description":"Federal and state privacy and transparency obligations for a Delaware C-Corporation. Covers BOI/FinCEN CTA, published policies, and B2B DPA when applicable. Does not provide legal advice.","last_researched":"2026-06-18","estimated_total_time":"1–2 weeks (policy publish + BOI filing)","estimated_total_cost":"FinCEN BOI: $0 direct; Termly free tier or paid; franchise tax separate (recurring)","legal_basis":["Corporate Transparency Act (FinCEN BOI)","Delaware Personal Data Privacy Act (DPDPA, effective January 1 2025)","FTC Safeguards Rule (if handling consumer financial NPI)","CCPA/CPRA (if California consumers)"],"intake_questions":[{"id":"sells_to","label":"Who do you sell to?","type":"select","required":true,"options":["B2B","Consumers","Both"],"maps_to":"clients.sells_to","affects":["privacy_policy","dpa","ccpa_triggers"]},{"id":"has_website","label":"Do you have a public website or app?","type":"boolean","required":true},{"id":"user_states","label":"US states where your users or customers reside (select all that apply)","type":"multiselect","required":true,"options":["Delaware","California","New York","Texas","Other","None yet / pre-launch"],"affects":["state_privacy_laws"]},{"id":"uses_analytics","label":"Do you use analytics or marketing cookies?","type":"boolean","required":true,"show_if":{"has_website":true}},{"id":"handles_payment_data","label":"Do you store or process payment card or bank account data directly (not via Stripe-class processor only)?","type":"boolean","required":true,"affects":["ftc_safeguards_note"]},{"id":"b2b_processes_customer_data","label":"As a B2B vendor, do you process personal data on behalf of business customers?","type":"boolean","required":true,"show_if":{"sells_to":["B2B","Both"]},"affects":["dpa"]},{"id":"website_url","label":"Public website URL","type":"url","required":false,"show_if":{"has_website":true}}],"steps":[{"id":"compliance_intake","title":"Complete compliance intake","description":"Maps which federal and state obligations apply to your C-Corp.","required":true,"action_type":"intake","accept":["all required intake_questions answered"]},{"id":"boi_fincen_filing","title":"File Beneficial Ownership Information (BOI) with FinCEN","description":"Corporate Transparency Act reporting. Most companies formed after 2024 must file within 30 days of formation or registration. Upload filing confirmation.","required":true,"estimated_fee":"$0","action_type":"artifact","artifact_kind":"boi_fincen_confirmation","url":"https://www.fincen.gov/boi","cta":"Open FinCEN BOI","processing_time":"Same day online","accept":["artifact_path or confirmation ID uploaded","status active"],"vault_proof":{"category":"compliance_boi","label":"FinCEN BOI filing confirmation","required":true},"penalty_note":"Civil and criminal penalties for willful failure to file."},{"id":"privacy_policy","title":"Publish Privacy Policy","description":"Policy covering data collected, purposes, retention, rights, and subprocessors. Include Delaware DPDPA rights if you target Delaware residents. Include CCPA section if California consumers.","required":true,"action_type":"artifact","artifact_kind":"privacy_policy","partner":{"slug":"termly","mode":"manual_v1","url":"https://termly.io","cta":"Open Termly"},"accept":["hosted_url OR artifact_path","status active","effective_at recorded"]},{"id":"terms_of_service","title":"Publish Terms of Service","description":"SaaS or product terms. UPL-safe language if offering business formation adjacent services.","required":true,"required_if":{"has_website":true},"action_type":"artifact","artifact_kind":"terms_of_service","partner":{"slug":"termly","mode":"manual_v1","url":"https://termly.io"},"accept":["hosted_url OR artifact_path","status active"]},{"id":"cookie_consent","title":"Deploy cookie consent","description":"Required for consumer-facing sites with non-essential cookies.","required":false,"required_if":{"uses_analytics":true},"action_type":"artifact","artifact_kind":"cookie_consent_config","partner":{"slug":"termly","mode":"manual_v1","url":"https://termly.io/products/cookie-consent-manager/"},"accept":["embed or URL proof","status active"]},{"id":"dpa","title":"Client Data Processing Agreement (B2B)","description":"When you process personal data for business customers, offer a DPA covering subprocessors and security measures.","required":false,"required_if":{"b2b_processes_customer_data":true},"action_type":"artifact","artifact_kind":"dpa","template_source":"documents/Onboardin - Client DPA Template.md","accept":["artifact_path uploaded","status active"],"note":"Counsel review recommended before sending to enterprise customers."},{"id":"vendor_processor_list","title":"Document key subprocessors","description":"List vendors that process customer data (Supabase, Stripe, Resend, analytics). Attach to privacy policy annex.","required":true,"action_type":"upload","artifact_kind":"subprocessor_list","template_source":"documents/Client Step 06 Templates/Subprocessor List.md","accept":["artifact_path uploaded","status active"],"vault_proof":{"category":"compliance_subprocessors","label":"Subprocessor list","required":true}},{"id":"ftc_safeguards_ack","title":"FTC Safeguards acknowledgment","description":"If you handle consumer financial NPI beyond a payment processor, document access controls and MFA on systems holding tax IDs or account numbers.","required":false,"required_if":{"handles_payment_data":true},"action_type":"upload","artifact_kind":"ftc_safeguards_summary","accept":["artifact_path uploaded","status active"],"note":"Concierge escalation if full WISP-level program required."}],"accept_criteria":["compliance_intake complete","boi_fincen_filing active","privacy_policy active","terms_of_service active when has_website is true","cookie_consent active when uses_analytics is true","dpa active when b2b_processes_customer_data is true","vendor_processor_list active","ftc_safeguards_ack active when handles_payment_data is true"],"recurring_obligation_seeds":[{"slug":"de-franchise-tax","title":"Delaware franchise tax","authority":"Delaware Division of Corporations","frequency":"annual","action_url":"https://corp.delaware.gov/","note":"Seed when lifecycle active. Not a Step 06 gate."},{"slug":"de-annual-report","title":"Delaware annual report","authority":"Delaware","frequency":"annual","note":"Seed when lifecycle active (Ticket #08)."}],"agent_instructions":["Guide Delaware C-Corp clients through us-de-c-corp-privacy only.","BOI filing is mandatory for most venture C-Corps; confirm formation date against CTA deadlines.","DPDPA applies when targeting Delaware residents; CCPA when California consumers.","Franchise tax and annual reports are recurring obligations, not Step 06 completion gates.","Do not provide legal advice."]}'::jsonb
),

(
  'us-de-llc-privacy',
  'US Delaware LLC — Privacy & Compliance',
  'Delaware',
  'LLC',
  'Federal transparency and state privacy obligations for a Delaware LLC. Nexus intake covers formation state plus states where you sell or hire. Does not provide legal advice.',
  '{"id":"us-de-llc-privacy","procedure_kind":"compliance","pipeline_step":6,"name":"US Delaware LLC — Privacy & Compliance","jurisdiction":"Delaware","entity_type":"LLC","formation_slug":"us-de-llc","description":"Federal transparency and state privacy obligations for a Delaware LLC. Nexus intake covers formation state plus states where you sell or hire. Does not provide legal advice.","last_researched":"2026-06-18","estimated_total_time":"1–2 weeks","estimated_total_cost":"FinCEN BOI: $0 direct; Termly free tier or paid; state annual reports vary","legal_basis":["Corporate Transparency Act (FinCEN BOI)","Delaware Personal Data Privacy Act (DPDPA)","CCPA/CPRA (California consumers)","State LLC annual report requirements (formation state + foreign qualification states)"],"intake_questions":[{"id":"sells_to","label":"Who do you sell to?","type":"select","required":true,"options":["B2B","Consumers","Both"],"maps_to":"clients.sells_to"},{"id":"formation_state","label":"State where LLC was formed","type":"select","required":true,"default":"Delaware","options":["Delaware","Wyoming","Other"],"maps_to":"clients.jurisdiction"},{"id":"operating_states","label":"States where you have customers, employees, or physical presence","type":"multiselect","required":true,"options":["Delaware","California","New York","Texas","Florida","Other","None yet / pre-launch"],"affects":["state_privacy_nexus","foreign_qualification_note"]},{"id":"has_website","label":"Do you have a public website or app?","type":"boolean","required":true},{"id":"uses_analytics","label":"Do you use analytics or marketing cookies?","type":"boolean","required":true,"show_if":{"has_website":true}},{"id":"has_contractors","label":"Do contractors or agencies access customer personal data?","type":"boolean","required":true,"affects":["contractor_dpa"]},{"id":"b2b_processes_customer_data","label":"Do you process personal data on behalf of business customers?","type":"boolean","required":true,"show_if":{"sells_to":["B2B","Both"]},"affects":["dpa"]},{"id":"website_url","label":"Public website URL","type":"url","required":false,"show_if":{"has_website":true}}],"steps":[{"id":"compliance_intake","title":"Complete compliance intake","description":"Maps nexus: formation state plus states where you sell or hire.","required":true,"action_type":"intake","accept":["all required intake_questions answered"]},{"id":"nexus_summary","title":"Confirm privacy law nexus","description":"Onboardin generates a short summary of which state privacy laws likely apply based on intake. Review and acknowledge.","required":true,"action_type":"acknowledge","artifact_kind":"privacy_nexus_summary","accept":["artifact generated and acknowledged"]},{"id":"boi_fincen_filing","title":"File Beneficial Ownership Information (BOI) with FinCEN","description":"Most LLCs must report beneficial owners to FinCEN. File and upload confirmation.","required":true,"estimated_fee":"$0","action_type":"artifact","artifact_kind":"boi_fincen_confirmation","url":"https://www.fincen.gov/boi","cta":"Open FinCEN BOI","accept":["confirmation uploaded","status active"],"vault_proof":{"category":"compliance_boi","label":"FinCEN BOI filing confirmation","required":true}},{"id":"privacy_policy","title":"Publish Privacy Policy","description":"Policy aligned to intake: B2B SaaS, e-commerce, or services template via Termly. Include state-specific sections flagged in nexus summary.","required":true,"action_type":"artifact","artifact_kind":"privacy_policy","partner":{"slug":"termly","mode":"manual_v1","url":"https://termly.io","cta":"Open Termly"},"accept":["hosted_url OR artifact_path","status active"]},{"id":"terms_of_service","title":"Publish Terms of Service","required":true,"required_if":{"has_website":true},"action_type":"artifact","artifact_kind":"terms_of_service","partner":{"slug":"termly","mode":"manual_v1","url":"https://termly.io"},"accept":["hosted_url OR artifact_path","status active"]},{"id":"cookie_consent","title":"Deploy cookie consent","required":false,"required_if":{"uses_analytics":true},"action_type":"artifact","artifact_kind":"cookie_consent_config","partner":{"slug":"termly","mode":"manual_v1","url":"https://termly.io/products/cookie-consent-manager/"},"accept":["embed or URL proof","status active"]},{"id":"dpa","title":"Client Data Processing Agreement","required":false,"required_if":{"b2b_processes_customer_data":true},"action_type":"artifact","artifact_kind":"dpa","template_source":"documents/Onboardin - Client DPA Template.md","accept":["artifact_path uploaded","status active"]},{"id":"subprocessor_list","title":"Document key subprocessors","description":"List vendors that process customer data. Attach to privacy policy annex.","required":true,"action_type":"upload","artifact_kind":"subprocessor_list","template_source":"documents/Client Step 06 Templates/Subprocessor List.md","accept":["artifact_path uploaded","status active"],"vault_proof":{"category":"compliance_subprocessors","label":"Subprocessor list","required":true}},{"id":"contractor_dpa","title":"Contractor / vendor DPAs","description":"If contractors access customer data, use contractor agreements with data protection clauses.","required":false,"required_if":{"has_contractors":true},"action_type":"upload","artifact_kind":"contractor_dpa_template","accept":["artifact_path uploaded","status active"],"note":"IP & Contract Templates (Step 05) may supply base template when live."},{"id":"operating_agreement_data_clause","title":"Confirm operating agreement data clause","description":"Multi-member LLCs: confirm operating agreement addresses member data sharing and company processing roles.","required":false,"required_if":{"entity_members":"multi"},"action_type":"acknowledge","accept":["acknowledged or upload of relevant section"],"note":"Single-member LLCs may waive with acknowledgment."}],"accept_criteria":["compliance_intake complete","nexus_summary acknowledged","boi_fincen_filing active","privacy_policy active","terms_of_service active when has_website is true","cookie_consent active when uses_analytics is true","dpa active when b2b_processes_customer_data is true","subprocessor_list active","contractor_dpa active when has_contractors is true"],"recurring_obligation_seeds":[{"slug":"llc-annual-report","title":"LLC annual report (formation state)","authority":"State SOS","frequency":"annual","note":"Delaware LLC annual tax/franchise; Wyoming annual report if us-wy-llc. Seed on lifecycle active."}],"agent_instructions":["Guide through us-de-llc-privacy. For Wyoming LLC use the us-wy-llc-privacy procedure.","Nexus intake drives which state privacy laws to mention; do not invent state obligations.","BOI is federal and required for most LLCs.","Annual reports are recurring, not Step 06 gates.","Do not provide legal advice."]}'::jsonb
)

