(
  'us-wy-llc-privacy',
  'US Wyoming LLC — Privacy & Compliance',
  'Wyoming',
  'LLC',
  'Federal privacy obligations and published policies for a Wyoming LLC. Wyoming has no comprehensive state consumer privacy law as of 2026; nexus intake flags other states (e.g. California). Domestic U.S.-formed Wyoming LLCs are not FinCEN reporting companies under the March 2025 interim final rule. Does not provide legal advice.',
  '{"id":"us-wy-llc-privacy","procedure_kind":"compliance","pipeline_step":6,"name":"US Wyoming LLC — Privacy & Compliance","jurisdiction":"Wyoming","entity_type":"LLC","formation_slug":"us-wy-llc","description":"Federal privacy obligations and published policies for a Wyoming LLC. Wyoming has no comprehensive state consumer privacy law as of 2026; nexus intake flags other states (e.g. California). Domestic U.S.-formed Wyoming LLCs are not FinCEN reporting companies under the March 2025 interim final rule. Does not provide legal advice.","last_researched":"2026-06-19","estimated_total_time":"1–2 weeks","estimated_total_cost":"Termly free tier or paid; Wyoming annual report $60/yr (recurring, not Step 06)","legal_basis":["FTC Safeguards Rule (if handling consumer financial NPI)","CCPA/CPRA (California consumers)","Other state privacy laws where operating_states nexus applies","FinCEN BOI (domestic U.S.-formed LLCs exempt under FinCEN March 2025 interim final rule — monitor for final rule)"],"intake_questions":[{"id":"sells_to","label":"Who do you sell to?","type":"select","required":true,"options":["B2B","Consumers","Both"],"maps_to":"clients.sells_to"},{"id":"formation_state","label":"State where LLC was formed","type":"select","required":true,"default":"Wyoming","options":["Wyoming"],"maps_to":"clients.jurisdiction"},{"id":"operating_states","label":"States where you have customers, employees, or physical presence","type":"multiselect","required":true,"options":["Wyoming","California","New York","Texas","Florida","Delaware","Other","None yet / pre-launch"],"affects":["state_privacy_nexus","foreign_qualification_note"]},{"id":"foreign_formed","label":"Was this LLC formed outside the United States?","type":"boolean","required":true,"affects":["boi_status"],"helper":"If you formed in the U.S. (e.g. Wyoming Articles of Organization), answer No — even if you live abroad."},{"id":"has_website","label":"Do you have a public website or app?","type":"boolean","required":true},{"id":"uses_analytics","label":"Do you use analytics or marketing cookies?","type":"boolean","required":true,"show_if":{"has_website":true}},{"id":"has_contractors","label":"Do contractors or agencies access customer personal data?","type":"boolean","required":true,"affects":["contractor_dpa"]},{"id":"b2b_processes_customer_data","label":"Do you process personal data on behalf of business customers?","type":"boolean","required":true,"show_if":{"sells_to":["B2B","Both"]},"affects":["dpa"]},{"id":"website_url","label":"Public website URL","type":"url","required":false,"show_if":{"has_website":true}}],"steps":[{"id":"compliance_intake","title":"Complete compliance intake","description":"Maps where you operate and sell. Drives which state privacy laws to address in your policy.","required":true,"action_type":"intake","accept":["all required intake_questions answered"]},{"id":"nexus_summary","title":"Confirm privacy law nexus","description":"Onboardin generates a short summary of which state privacy laws likely apply. Wyoming formation alone does not trigger Delaware DPDPA.","required":true,"action_type":"acknowledge","artifact_kind":"privacy_nexus_summary","accept":["artifact generated and acknowledged"]},{"id":"boi_status","title":"Confirm BOI / FinCEN status","description":"Domestic U.S.-formed Wyoming LLCs: acknowledge FinCEN March 2025 interim final rule exemption and monitor fincen.gov/boi for final rule updates. Foreign-formed LLCs registered in the U.S.: use the FinCEN filing step instead.","required":true,"required_if":{"foreign_formed":false},"action_type":"acknowledge","artifact_kind":"boi_exemption_acknowledgment","url":"https://www.fincen.gov/boi","cta":"FinCEN BOI guidance","accept":["boi_exemption_acknowledgment active"],"note":"Shown only when foreign_formed is false. When true, complete boi_fincen_filing instead."},{"id":"boi_fincen_filing","title":"File FinCEN BOI (foreign-formed only)","description":"Required when foreign_formed is true. Upload filing confirmation.","required":false,"required_if":{"foreign_formed":true},"action_type":"artifact","artifact_kind":"boi_fincen_confirmation","url":"https://www.fincen.gov/boi","cta":"Open FinCEN BOI","vault_proof":{"category":"compliance_boi","label":"FinCEN BOI filing confirmation","required":true}},{"id":"privacy_policy","title":"Publish Privacy Policy","description":"Policy aligned to intake via Termly. Include CCPA and other state sections flagged in nexus summary.","required":true,"action_type":"artifact","artifact_kind":"privacy_policy","partner":{"slug":"termly","mode":"manual_v1","url":"https://termly.io","cta":"Open Termly"},"accept":["hosted_url OR artifact_path","status active"]},{"id":"terms_of_service","title":"Publish Terms of Service","required":true,"required_if":{"has_website":true},"action_type":"artifact","artifact_kind":"terms_of_service","partner":{"slug":"termly","mode":"manual_v1","url":"https://termly.io"},"accept":["hosted_url OR artifact_path","status active"]},{"id":"cookie_consent","title":"Deploy cookie consent","required":false,"required_if":{"uses_analytics":true},"action_type":"artifact","artifact_kind":"cookie_consent_config","partner":{"slug":"termly","mode":"manual_v1","url":"https://termly.io/products/cookie-consent-manager/"},"accept":["embed or URL proof","status active"]},{"id":"dpa","title":"Client Data Processing Agreement","required":false,"required_if":{"b2b_processes_customer_data":true},"action_type":"artifact","artifact_kind":"dpa","template_source":"documents/Onboardin - Client DPA Template.md","accept":["artifact_path uploaded","status active"]},{"id":"subprocessor_list","title":"Document key subprocessors","description":"List vendors that process customer data. Attach to privacy policy annex.","required":true,"action_type":"upload","artifact_kind":"subprocessor_list","template_source":"documents/Client Step 06 Templates/Subprocessor List.md","accept":["artifact_path uploaded","status active"],"vault_proof":{"category":"compliance_subprocessors","label":"Subprocessor list","required":true}},{"id":"contractor_dpa","title":"Contractor / vendor DPAs","required":false,"required_if":{"has_contractors":true},"action_type":"upload","artifact_kind":"contractor_dpa_template","accept":["artifact_path uploaded","status active"]}],"accept_criteria":["compliance_intake complete","nexus_summary acknowledged","boi_status active when foreign_formed is false","boi_fincen_filing active when foreign_formed is true","privacy_policy active","terms_of_service active when has_website is true","cookie_consent active when uses_analytics is true","dpa active when b2b_processes_customer_data is true","subprocessor_list active","contractor_dpa active when has_contractors is true"],"recurring_obligation_seeds":[{"slug":"llc-annual-report","title":"Wyoming annual report","authority":"Wyoming Secretary of State","frequency":"annual","note":"Due 1st of formation anniversary month. $60/yr. Seed via seed_us_llc_obligations state=WY on lifecycle active."}],"agent_instructions":["Guide through us-wy-llc-privacy. Formation slug us-wy-llc.","Wyoming has no DPDPA-equivalent state law; cite operating_states for California and other nexus laws.","Domestic Wyoming LLCs: acknowledge BOI exemption unless foreign_formed is true.","Annual report is recurring (#08 calendar), not a Step 06 gate.","Do not provide legal advice."]}'::jsonb
)
)

on conflict (slug) do update set
  name = excluded.name,
  jurisdiction = excluded.jurisdiction,
  entity_type = excluded.entity_type,
  description = excluded.description,
  blueprint = excluded.blueprint,
  updated_at = now();
